/** JSONPath extraction spec for an ApiCall step's JSON response. */
export interface ExtractSpec {
  /** JSONPath expression, e.g. `$.issues[*].key`. */
  path: string;
  /** Default value when path resolves to nothing. */
  fallback?: unknown | null;
  /** If true, empty extraction → `status: NO_RESULTS` (for on_result routing). */
  fail_on_empty?: boolean;
}

/** Pagination strategy for an ApiCall step. */
export type PaginationSpec =
  | { type: "None" }
  | { type: "Auto"; max_pages?: number | null }
  | { type: "Offset"; start_param: string; limit_param: string; limit: number; total_path: string; max_pages?: number | null }
  | { type: "Cursor"; cursor_param: string; next_path: string; max_pages?: number | null }
  | { type: "Page"; page_param: string; page_size_param: string; page_size: number; has_more_path: string; max_pages?: number | null };

export type StepType =
  | { type: "Agent" }
  | { type: "ApiCall" }
  | { type: "BatchQuickPrompt" }
  | { type: "Notify" }
  | { type: "Gate" }
  | { type: "Exec" }
  | { type: "BatchApiCall" }
  | { type: "JsonData" };

export type StepMode =
  | { type: "Normal" };

export interface AgentSettings {
  model?: string | null;
  tier?: ModelTier | null;
  reasoning_effort?: string | null;
  max_tokens?: number | null;
}

export interface StepConditionRule {
  contains: string;
  action: ConditionAction;
}

export type ConditionAction =
  | { type: "Stop" }
  | { type: "Skip" }
  /** 0.7.0 Phase 6 — `max_iterations` caps how many times THIS Goto fires
   *  before the runner falls through. `null` = no per-edge limit (only the
   *  workflow-level loop_detection guard applies). */
  | { type: "Goto"; step_name: string; max_iterations?: number | null };

export interface RetryConfig {
  max_retries: number;
  backoff: string;
}

export type WorkflowAction =
  | { type: "CreatePr"; title_template: string; body_template: string; branch_template: string }
  | { type: "CommentIssue"; body_template: string }
  | { type: "UpdateTrackerStatus"; status: string }
  | { type: "CreateIssue"; title_template: string; body_template: string };

