export interface StepResult {
  step_name: string;
  status: RunStatus;
  output: string;
  tokens_used: number;
  duration_ms: number;
  /** 0.8.2 — Wall-clock timestamp at which the step started executing.
   *  Optional for backward compatibility with runs predating the field.
   *  Drives the WorkflowDetail page's "live progress" view after navigation
   *  (synthesized liveRun) and the gate's actual pause duration. */
  started_at?: string | null;
  condition_result?: string | null;
  /**
   * For output_format=Structured only: did the agent produce the
   * ---STEP_OUTPUT--- envelope (possibly after repair).
   * true = envelope found, .data/.summary/.status populated downstream.
   * false = Structured requested but extraction failed even after repair.
   * null/undefined = FreeText step, the concept does not apply.
   */
  envelope_detected?: boolean | null;
  /** Snapshot of `step.step_type.type` at execution time. `null` for
   *  rows written before this field existed. */
  step_kind?: string | null;
  /** Snapshot of `step.agent` for Agent steps. */
  step_agent?: AgentType | null;
  /** Snapshot of `step.api_plugin_slug` for ApiCall steps. */
  step_api_plugin_slug?: string | null;
  /** Snapshot of `step.api_endpoint_path` for ApiCall steps. */
  step_api_endpoint_path?: string | null;
}

